// Construire la réponse pour l'extension
const searchResult = $('Chercher contact HubSpot').first().json;
const total = searchResult.body?.total || 0;

if (total > 0) {
  const contact = searchResult.body.results[0];
  const props = contact.properties || {};

  // Mapper les valeurs enum vers des labels lisibles
  const statusLabels = {
    'message_vocal_laisse': 'Message vocal laissé',
    'email_envoye': 'Email envoyé',
    'injoignable': 'Injoignable',
    'rendez_vous_pris': 'Rendez-vous pris',
    'ne_plus_rappeler': 'Ne plus rappeler',
    'deja_appele': 'Déjà appelé',
    'pas_interesse': 'Pas intéressé',
    'deja_en_partenariat': 'Déjà en partenariat',
    'a_raccroche': 'A raccroché'
  };

  return [{
    json: {
      exists: true,
      contact_id: contact.id,
      firstname: props.firstname || '',
      lastname: props.lastname || '',
      last_status: statusLabels[props.statut_prospection_decidento] || props.statut_prospection_decidento || '',
      last_date: props.lastmodifieddate || props.createdate || '',
      commercial: props.commercial_decidento || '',
      owner_id: props.hubspot_owner_id || ''
    }
  }];
} else {
  return [{
    json: {
      exists: false
    }
  }];
}
